import React from 'react';

const photos = [
  { src: 'https://images.unsplash.com/photo-1602002418082-a4443e081dd1?w=800&q=80', label: 'Overwater Villa', wide: true },
  { src: 'https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=500&q=80', label: 'Deluxe Room' },
  { src: 'https://images.unsplash.com/photo-1571003123894-1f0594d2b5d9?w=500&q=80', label: 'Infinity Pool' },
  { src: 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=500&q=80', label: 'Dining Area' },
  { src: 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80', label: 'Beachfront', wide: true },
  { src: 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=500&q=80', label: 'Ocean View' },
];

function Gallery() {
  return (
    <div id="gallery" className="gallery-bg">
      <div className="gallery-inner">
        <p className="section-tag">Photo Gallery</p>
        <h2 style={{ fontFamily: "'Playfair Display', serif", color: '#1a3a3a', marginTop: 10, fontSize: 'clamp(1.8rem, 3.5vw, 2.8rem)' }}>
          A Glimpse of Paradise
        </h2>

        <div className="gallery-grid">
          {photos.map((p) => (
            <div key={p.label} className={p.wide ? 'wide' : ''}>
              <img src={p.src} alt={p.label} loading="lazy" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Gallery;
